[
  {
    "text": "The Hagan et al. LiDAR classification product was derived from a continuous probability surface that is accessible at the identical 10 m resolution and over the same Maine extent.",
    "topic": "data provenance"
  },
  {
    "text": "The LSOG mapping product and the Hagan et al. LiDAR product use the same definition of LSOG presence (e.g., basal area threshold, minimum patch size).",
    "topic": "definition harmonization"
  },
  {
    "text": "The LSOG probability map can be converted to a discrete classification using a threshold that matches the design-based FIA error structure.",
    "topic": "conversion feasibility"
  },
  {
    "text": "A pixel-level validation set, independent of both FIA plots and the LiDAR training data, exists for the Maine study area and can serve as a common reference.",
    "topic": "common reference"
  }
]
